#include <bits/stdc++.h>
using namespace std;
int a[5005],b[5005],len=0;
int main(){
	string s;
	int jz;
	cin>>jz;
	cin>>s;
	for(int i=0;i<s.size();i++){
		if(s[s.size()-i-1]>='A' && s[s.size()-i-1]<='Z')a[i+1]=s[s.size()-i-1]-'A'+10;
		else a[i+1]=s[s.size()-i-1]-'0';
	}
	len=s.size();
	cin>>s;
	for(int i=0;i<s.size();i++){
		if(s[s.size()-i-1]>='A' && s[s.size()-i-1]<='Z')b[i+1]=s[s.size()-i-1]-'A'+10;
		else b[i+1]=s[s.size()-i-1]-'0';
	}
	if(s.size()>len)len=s.size();
	for(int i=1;i<=len;i++){
		a[i]+=b[i];
		a[i+1]+=a[i]/jz;
		a[i]%=jz;
	}
	if(a[len+1])len++;
	for(int i=len;i>0;i--){
		if(a[i]>9)cout<<char('A'+(a[i]-10));
		else cout<<a[i];
	}
	return 0;
}
